class Fancy:
    def __init__(self):
        self.sequence = []

    def append(self, val):
        self.sequence.append(val)

    def addAll(self, inc):
        self.sequence = [num + inc for num in self.sequence]

    def multAll(self, m):
        self.sequence = [num * m for num in self.sequence]

    def getIndex(self, idx):
        if idx >= len(self.sequence):
            return -1
        return self.sequence[idx]
```


